\begin{align*}
\frac{AB}{AC} &= \frac{DE}{DC} \\
\frac{AB}{3\text{m}} &= \frac{1.5\text{m}}{0.5\text{m}} = 3 \\
AB &= 3 \cdot 3\text{m} = \boxed{9}\text{ meters}.
